_aggregate_1":"","match_event_aggregate_2":"","match_event_aggregate_3":"","mom":"0","namespace":"0","parrySaves":"0","passattempts":"13","passesmade":"9","pos":"defender","punchSaves":"0","rating":"6.20","realtimegame":"927","realtimeidle":"40","redcards":"0","reflexSaves":"0","saves":"0","SCORE":"2","secondsPlayed":"5472","shots":"0","tackleattempts":"3","tacklesmade":"0","userResult":"0","vproattr":"NH","vprohackreason":"0","wins":"0","playername":"Abdel-13_0"},"1006426422687":{"archetypeid":"10","assists":"0","ballDiveSaves":"0","cleansheetsany":"0","cleansheetsdef":"0","cleansheetsgk":"0","crossSaves":"0","gameTime":"5472","goals":"1","goalsconceded":"4","goodDirectionSaves":"0","losses":"0","match_event_aggregate_0":"","match_event_aggregate_1":"","match_event_aggregate_2":"","match_event_aggregate_3":"","mom":"0","namespace":"0","parrySaves":"0","passattempts":"21","passesmade":"17","pos":"forward","punchSaves":"0","rating":"7.70","realtimegame":"927","realtimeidle":"31","redcards":"0","reflexSaves":"0","saves":"0","SCORE":"2","secondsPlayed":"5472","shots":"1","tackleattempts":"5","tacklesmade":"2","userResult":"0","vproattr":"NH","vprohackreason":"0","wins":"0","playername":"zerug0_"},"1007972434004":{"archetypeid":"8","assists":"0","ballDiveSaves":"0","cleansheetsany":"0","cleansheetsdef":"0","cleansheetsgk":"0","crossSaves":"0","gameTime":"5472","goals":"0","goalsconceded":"4","goodDirectionSaves":"0","losses":"0","match_event_aggregate_0":"","match_event_aggregate_1":"","match_event_aggregate_2":"","match_event_aggregate_3":"","mom":"0","namespace":"0","parrySaves":"0","passattempts":"19","passesmade":"17","pos":"midfielder","punchSaves":"0","rating":"8.30","realtimegame":"927","realtimeidle":"9","redcards":"0","reflexSaves":"0","saves":"0","SCORE":"2","secondsPlayed":"5472","shots":"0","tackleattempts":"2","tacklesmade":"2","userResult":"0","vproattr":"NH","vprohackreason":"0","wins":"0","playername":"Nasco_Te_Fimbu"},"1008800793672":{"archetypeid":"10","assists":"0","ballDiveSaves":"0","cleansheetsany":"0","cleansheetsdef":"0","cleansheetsgk":"0","crossSaves":"0","gameTime":"5472","goals":"1","goalsconceded":"4","goodDirectionSaves":"0","losses":"0","match_event_aggregate_0":"","match_event_aggregate_1":"","match_event_aggregate_2":"","match_event_aggregate_3":"","mom":"0","namespace":"0","parrySaves":"0","passattempts":"12","passesmade":"10","pos":"forward","punchSaves":"0","rating":"6.90","realtimegame":"3681","realtimeidle":"0","redcards":"0","reflexSaves":"0","saves":"0","SCORE":"2","secondsPlayed":"5472","shots":"5","tackleattempts":"3","tacklesmade":"0","userResult":"0","vproattr":"NH","vprohackreason":"0","wins":"0","playername":"dark_kise7"}}},"aggregate":{"414707":{"archetypeid":85,"assists":3,"ballDiveSaves":0,"cleansheetsany":0,"cleansheetsdef":0,"cleansheetsgk":0,"crossSaves":0,"gameTime":60192,"goals":4,"goalsconceded":22,"goodDirectionSaves":2,"losses":0,"match_event_aggregate_0":0,"match_event_aggregate_1":0,"match_event_aggregate_2":0,"match_event_aggregate_3":0,"mom":1,"namespace":0,"parrySaves":0,"passattempts":204,"passesmade":176,"pos":0,"punchSaves":0,"rating":83.4,"realtimegame":16915,"realtimeidle":446,"redcards":0,"reflexSaves":1,"saves":3,"SCORE":44,"secondsPlayed":60192,"shots":6,"tackleattempts":31,"tacklesmade":11,"userResult":0,"vproattr":0,"vprohackreason":0,"wins":0},"2148207":{"archetypeid":77,"assists":1,"ballDiveSaves":0,"cleansheetsany":0,"cleansheetsdef":0,"cleansheetsgk":0,"crossSaves":0,"gameTime":60192,"goals":2,"goalsconceded":44,"goodDirectionSaves":1,"losses":0,"match_event_aggregate_0":0,"match_event_aggregate_1":0,"match_event_aggregate_2":0,"match_event_aggregate_3":0,"mom":0,"namespace":0,"parrySaves":0,"passattempts":138,"passesmade":111,"pos":0,"punchSaves":0,"rating":73.2,"realtimegame":39599,"realtimeidle":338,"redcards":0,"reflexSaves":0,"saves":1,"SCORE":22,"secondsPlayed":60192,"shots":6,"tackleattempts":37,"tacklesmade":6,"userResult":0,"vproattr":0,"vprohackreason":0,"wins":0}}}]
$cpelite_json$::jsonb;
    v_imported_matches integer := 0;
begin
    select "Id"
    into v_team_id
    from "Teams"
    where "EaClubId" = v_ea_club_id
      and "IsArchived" = false
    order by "CreatedAt"
    limit 1;

    if v_team_id is null then
        raise exception 'Cannot import EA matches: no active team found with EaClubId=%', v_ea_club_id;
    end if;

    create temp table tmp_seed_ea_matches
    (
        "MatchDbId" uuid primary key,
        "EaMatchId" text not null unique,
        "MatchJson" jsonb not null,
        "PlayedAt" timestamptz not null,
        "HomeEaClubId" bigint not null,
        "HomeClubName" text,
        "HomeScore" integer not null,
        "AwayEaClubId" bigint not null,
        "AwayClubName" text,
        "AwayScore" integer not null
    ) on commit drop;

    insert into tmp_seed_ea_matches
    (
        "MatchDbId",
        "EaMatchId",
        "MatchJson",
        "PlayedAt",
        "HomeEaClubId",
        "HomeClubName",
        "HomeScore",
        "AwayEaClubId",
        "AwayClubName",
        "AwayScore"
    )
    with source_matches as
    (
        select
            item.value as match_json,
            item.value ->> 'matchId' as match_id
        from jsonb_array_elements(v_payload) as item(value)
        where item.value ? 'matchId'
          and item.value ? 'timestamp'
          and item.value ? 'clubs'
          and jsonb_typeof(item.value -> 'clubs') = 'object'
    ),
    club_rows as
    (
        select
            source_matches.match_id,
            source_matches.match_json,
            club.key::bigint as ea_club_id,
            club.value as club_json,
            coalesce(nullif(club.value ->> 'score', '')::integer, nullif(club.value ->> 'goals', '')::integer, 0) as score,
            club.value #>> '{details,name}' as club_name,
            row_number() over
            (
                partition by source_matches.match_id
                order by case when club.key::bigint = v_ea_club_id then 0 else 1 end, club.key::bigint
            ) as club_rank
        from source_matches
        cross join lateral jsonb_each(source_matches.match_json -> 'clubs') as club(key, value)
    )
    select
        gen_random_uuid(),
        source_matches.match_id,
        source_matches.match_json,
        to_timestamp((source_matches.match_json ->> 'timestamp')::bigint),
        home.ea_club_id,
        home.club_name,
        home.score,
        away.ea_club_id,
        away.club_name,
        away.score
    from source_matches
    join club_rows home on home.match_id = source_matches.match_id and home.club_rank = 1
    join club_rows away on away.match_id = source_matches.match_id and away.club_rank = 2;

    select count(*) into v_imported_matches from tmp_seed_ea_matches;
    if v_imported_matches = 0 then
        raise exception 'Cannot import EA matches: payload did not contain valid matches.';
    end if;

    insert into "EaMatchSnapshots"
    (
        "Id",
        "TeamId",
        "EaClubId",
        "Platform",
        "MatchType",
        "RawJson",
        "SyncedAt"
    )
    values
    (
        gen_random_uuid(),
        v_team_id,
        v_ea_club_id,
        v_platform,
        'friendlyMatch',
        v_payload,
        v_synced_at
    )
    on conflict ("TeamId", "MatchType") do update
    set "RawJson" = excluded."RawJson",
        "SyncedAt" = excluded."SyncedAt";

    delete from "EaMatchClubStats" stat
    using "EaFriendlyMatches" match, tmp_seed_ea_matches seed
    where stat."EaFriendlyMatchId" = match."Id"
      and match."TeamId" = v_team_id
      and match."EaMatchId" = seed."EaMatchId";

    delete from "EaMatchPlayerStats" stat
    using "EaFriendlyMatches" match, tmp_seed_ea_matches seed
    where stat."EaFriendlyMatchId" = match."Id"
      and match."TeamId" = v_team_id
      and match."EaMatchId" = seed."EaMatchId";

    delete from "EaFriendlyMatches" match
    using tmp_seed_ea_matches seed
    where match."TeamId" = v_team_id
      and match."EaMatchId" = seed."EaMatchId";

    insert into "EaFriendlyMatches"
    (
        "Id",
        "TeamId",
        "EaClubId",
        "Platform",
        "EaMatchId",
        "PlayedAt",
        "MatchType",
        "HomeEaClubId",
        "HomeClubName",
        "HomeScore",
        "AwayEaClubId",
        "AwayClubName",
        "AwayScore",
        "RawJson",
        "SyncedAt",
        "TournamentMatchId"
    )
    select
        "MatchDbId",
        v_team_id,
        v_ea_club_id,
        v_platform,
        "EaMatchId",
        "PlayedAt",
        'friendlyMatch',
        "HomeEaClubId",
        "HomeClubName",
        "HomeScore",
        "AwayEaClubId",
        "AwayClubName",
        "AwayScore",
        "MatchJson",
        v_synced_at,
        null
    from tmp_seed_ea_matches;

    insert into "EaMatchClubStats"
    (
        "Id",
        "EaFriendlyMatchId",
        "TeamId",
        "EaClubId",
        "Goals",
        "Assists",
        "Rating",
        "Shots",
        "PassesMade",
        "PassAttempts",
        "TacklesMade",
        "TackleAttempts",
        "Saves",
        "GoalsConceded",
        "RedCards",
        "PlayerOfTheMatch",
        "Score",
        "Result",
        "Wins",
        "Losses",
        "Ties",
        "WinnerByDnf",
        "RegionId",
        "EaTeamId",
        "StadiumName",
        "CrestAssetId",
        "KitColor1",
        "KitColor2",
        "KitColor3",
        "KitColor4",
        "RawJson"
    )
    with club_ids as
    (
        select distinct seed."MatchDbId", seed."MatchJson", club_key.key as club_id
        from tmp_seed_ea_matches seed
        cross join lateral jsonb_object_keys(seed."MatchJson" -> 'clubs') as club_key(key)
        union
        select distinct seed."MatchDbId", seed."MatchJson", aggregate_key.key as club_id
        from tmp_seed_ea_matches seed
        cross join lateral jsonb_object_keys(coalesce(seed."MatchJson" -> 'aggregate', '{}'::jsonb)) as aggregate_key(key)
    )
    select
        gen_random_uuid(),
        club_ids."MatchDbId",
        v_team_id,
        club_ids.club_id::bigint,
        coalesce(nullif(aggregate_json.value ->> 'goals', '')::integer, nullif(club_json.value ->> 'goals', '')::integer, nullif(aggregate_json.value ->> 'SCORE', '')::integer, nullif(club_json.value ->> 'score', '')::integer),
        nullif(aggregate_json.value ->> 'assists', '')::integer,
        nullif(aggregate_json.value ->> 'rating', '')::double precision,
        nullif(aggregate_json.value ->> 'shots', '')::integer,
        nullif(aggregate_json.value ->> 'passesmade', '')::integer,
        nullif(aggregate_json.value ->> 'passattempts', '')::integer,
        nullif(aggregate_json.value ->> 'tacklesmade', '')::integer,
        nullif(aggregate_json.value ->> 'tackleattempts', '')::integer,
        nullif(aggregate_json.value ->> 'saves', '')::integer,
        coalesce(nullif(aggregate_json.value ->> 'goalsconceded', '')::integer, nullif(club_json.value ->> 'goalsAgainst', '')::integer),
        nullif(aggregate_json.value ->> 'redcards', '')::integer,
        nullif(aggregate_json.value ->> 'mom', '')::integer,
        nullif(club_json.value ->> 'score', '')::integer,
        club_json.value ->> 'result',
        nullif(club_json.value ->> 'wins', '')::integer,
        nullif(club_json.value ->> 'losses', '')::integer,
        nullif(club_json.value ->> 'ties', '')::integer,
        case lower(coalesce(club_json.value ->> 'winnerByDnf', ''))
            when '1' then true
            when 'true' then true
            when '0' then false
            when 'false' then false
            else null
        end,
        nullif(club_json.value #>> '{details,regionId}', '')::integer,
        coalesce(nullif(club_json.value #>> '{details,teamId}', '')::integer, nullif(club_json.value ->> 'TEAM', '')::integer),
        club_json.value #>> '{details,customKit,stadName}',
        club_json.value #>> '{details,customKit,crestAssetId}',
        club_json.value #>> '{details,customKit,kitColor1}',
        club_json.value #>> '{details,customKit,kitColor2}',
        club_json.value #>> '{details,customKit,kitColor3}',
        club_json.value #>> '{details,customKit,kitColor4}',
        jsonb_build_object('club', club_json.value, 'aggregate', aggregate_json.value)
    from club_ids
    cross join lateral (select coalesce(club_ids."MatchJson" -> 'clubs' -> club_ids.club_id, '{}'::jsonb) as value) as club_json
    cross join lateral (select coalesce(club_ids."MatchJson" -> 'aggregate' -> club_ids.club_id, '{}'::jsonb) as value) as aggregate_json;

    insert into "EaMatchPlayerStats"
    (
        "Id",
        "EaFriendlyMatchId",
        "TeamId",
        "EaClubId",
        "EaPlayerId",
        "PlayerName",
        "Position",
        "Goals",
        "Assists",
        "Rating",
        "PlayerOfTheMatch",
        "Shots",
        "PassesMade",
        "PassAttempts",
        "TacklesMade",
        "TackleAttempts",
        "Saves",
        "GoalsConceded",
        "SecondsPlayed",
        "VproAttributes",
        "CleanSheetsAny",
        "CleanSheetsDef",
        "CleanSheetsGk",
        "BallDiveSaves",
        "CrossSaves",
        "GoodDirectionSaves",
        "ParrySaves",
        "PunchSaves",
        "ReflexSaves",
        "RedCards",
        "GameTime",
        "RealtimeGame",
        "RealtimeIdle",
        "ArchetypeId",
        "MatchEventAggregate0",
        "MatchEventAggregate1",
        "MatchEventAggregate2",
        "MatchEventAggregate3",
        "RawJson"
    )
    select
        gen_random_uuid(),
        seed."MatchDbId",
        v_team_id,
        club_players.key::bigint,
        player.key,
        player.value ->> 'playername',
        player.value ->> 'pos',
        nullif(player.value ->> 'goals', '')::integer,
        nullif(player.value ->> 'assists', '')::integer,
        nullif(player.value ->> 'rating', '')::double precision,
        coalesce(nullif(player.value ->> 'mom', '')::integer, 0) = 1,
        nullif(player.value ->> 'shots', '')::integer,
        nullif(player.value ->> 'passesmade', '')::integer,
        nullif(player.value ->> 'passattempts', '')::integer,
        nullif(player.value ->> 'tacklesmade', '')::integer,
        nullif(player.value ->> 'tackleattempts', '')::integer,
        nullif(player.value ->> 'saves', '')::integer,
        nullif(player.value ->> 'goalsconceded', '')::integer,
        nullif(player.value ->> 'secondsPlayed', '')::integer,
        player.value ->> 'vproattr',
        nullif(player.value ->> 'cleansheetsany', '')::integer,
        nullif(player.value ->> 'cleansheetsdef', '')::integer,
        nullif(player.value ->> 'cleansheetsgk', '')::integer,
        nullif(player.value ->> 'ballDiveSaves', '')::integer,
        nullif(player.value ->> 'crossSaves', '')::integer,
        nullif(player.value ->> 'goodDirectionSaves', '')::integer,
        nullif(player.value ->> 'parrySaves', '')::integer,
        nullif(player.value ->> 'punchSaves', '')::integer,
        nullif(player.value ->> 'reflexSaves', '')::integer,
        nullif(player.value ->> 'redcards', '')::integer,
        nullif(player.value ->> 'gameTime', '')::integer,
        nullif(player.value ->> 'realtimegame', '')::integer,
        nullif(player.value ->> 'realtimeidle', '')::integer,
        nullif(player.value ->> 'archetypeid', '')::integer,
        player.value ->> 'match_event_aggregate_0',
        player.value ->> 'match_event_aggregate_1',
        player.value ->> 'match_event_aggregate_2',
        player.value ->> 'match_event_aggregate_3',
        player.value
    from tmp_seed_ea_matches seed
    cross join lateral jsonb_each(coalesce(seed."MatchJson" -> 'players', '{}'::jsonb)) as club_players(key, value)
    cross join lateral jsonb_each(club_players.value) as player(key, value)
    where player.value ? 'playername';

    raise notice 'Imported % EA friendly matches for team % / EA club %.', v_imported_matches, v_team_id, v_ea_club_id;
end $$;

commit;